  const ayahs: AyahProps[] = [
    { ayahId: 42, surahNumber: 2, pageNumber: 7, isComplete: true, continuesFromPrev: true, textData: "مِمَّا كَانَا فِيهِؐ وَقُلْنَا \"هْبِطُواْؐ بَعْضُكُمْ لِبَعْـضٖ عَدُوٌّؐ وَلَكُمْ فِى ۱لاَرْضِ مُسْتَقَرٌّ وَمَتَــٰع٘ اِلَيٰ حِينٍؐ" },
    { ayahId: 43, surahNumber: 2, pageNumber: 7, isComplete: true, continuesFromPrev: false, textData: "فَتَلَقّۭيٰٓ ءَادَمُ مِن رَّبِّهِ” كَلِمَـٰــتٍ فَتَابببَ عَلَيْهِؐ إِنَّهُ„ هُوَ ۰لتَّوَّابُ ۴لرَّحِيمُؐ" },
    { ayahId: 44, surahNumber: 2, pageNumber: 7, isComplete: true, continuesFromPrev: false, textData: "قُلْنَا \"هْبِطُواْ مِنْهَا جَمِيعاًؐ فَإِمَّا يَاتِيَنَّكُم مِّنِّى هُديً فَمَن تَبِعَ هُدۭايَ فَلاَ خَوْف٘ عَلَيْهِمْ وَلاَ هُمْ يَحْزَنُونَؐ" },
    { ayahId: 45, surahNumber: 2, pageNumber: 7, isComplete: true, continuesFromPrev: false, textData: "وَالذِينَ كَفَرُواْ وَكَذَّبُواْ بِـَٔايَـٰتِنَآ ٱُوْلَئِكَ أَصْحَــٰــبُ ۴لنّۭارۣ هُمْ فِيهَا خَـٰلِدُونَؐ" },
    { ayahId: 46, surahNumber: 2, pageNumber: 7, isComplete: true, continuesFromPrev: false, textData: "يَــٰبَنِىٓ إِسْرَآءِيلَ ۸ذْكُرُواْ نِعْمَتِـيَ ۰لتِىٓ أَنْعَمْـتُ عَلَيْكُمْ وَأَوْفُواْ بِعَهْدِﻯٓ ٱُوفِ بِعَهْدِكُمْ وَإِيَّـٰيَ فَارْهَبُونِؐ" },
    { ayahId: 47, surahNumber: 2, pageNumber: 7, isComplete: true, continuesFromPrev: false, textData: "وَءَامِنُواْ بِمَآ أَنزَلْــتُ مُصَدِّقاً لِّمَا مَعَكُمْ وَلاَ تَكُونُوٓاْ أَوَّلَ كَافِرۣۢ بِهِؐ/ وَلاَ تَشْتَرُواْ بِـَٔايَـٰتِى ثَمَناً قَلِيلًا وَإِيَّـٰيَ فَاتَّقُونِؐ ¥" },
    { ayahId: 48, surahNumber: 2, pageNumber: 7, isComplete: true, continuesFromPrev: false, textData: "وَلاَ تَلْبِسُواْ ۴لْحَقَّ بِالْبَـٰطِلِ وَتَكْتُمُواْ ۴لْحَقَّ وَأَنتُمْ تَعْلَمُونَؐ" },
    { ayahId: 49, surahNumber: 2, pageNumber: 7, isComplete: true, continuesFromPrev: false, textData: "وَأَقِيمُواْ ۴لصَّلَوٰةَ وَءَاتُواْ ۴لزَّكَوٰةَؐ وَارْكَعُواْ مَعَ ۰لرَّ؛كِعِينَؐ" },
    { ayahId: 50, surahNumber: 2, pageNumber: 7, isComplete: true, continuesFromPrev: false, textData: "أَتَامُرُونَ ۰لنَّاسَ بِالْبِرّۣ وَتَنسَوْنَ أَنفُسَكُمْ وَأَنتُمْ تَتْلُونَ ۰لْكِتَــٰــبَؐ أَفَلاَ تَعْقِلُونَؐ" },
    { ayahId: 51, surahNumber: 2, pageNumber: 7, isComplete: true, continuesFromPrev: false, textData: "وَاسْتَعِينُواْ بِالصَّبْرۣ وَالصَّلَوٰةِؐ وَإِنَّهَا لَكَبِيرَة٘ اِلاَّ عَلَي ۰لْخَــٰشِعِيـنَ" },
    { ayahId: 52, surahNumber: 2, pageNumber: 7, isComplete: false, continuesFromPrev: false, textData: "۰لذِينَ" }
  ];

